# -*- coding: utf-8 -*-

from __future__ import annotations

import base64

from PySide6.QtCore import Qt
from PySide6.QtGui import QPixmap


_CLEAROCR_LOGO_B64 = """"""


def clearocr_logo_pixmap(target_width: int = 300) -> QPixmap:
    raw = base64.b64decode(_CLEAROCR_LOGO_B64)
    pixmap = QPixmap()
    pixmap.loadFromData(raw, 'PNG')
    if target_width > 0 and not pixmap.isNull():
        pixmap = pixmap.scaledToWidth(target_width, Qt.SmoothTransformation)
    return pixmap
